import{_ as t,o as e,c as r,a2 as o}from"./chunks/framework.DnrXFDHb.js";const p=JSON.parse('{"title":"","description":"","frontmatter":{},"headers":[],"relativePath":"審計報告庫/財務審計/6903_巨漢/20260502/F07_存貨週轉效率同業對比_投資研究員.md","filePath":"審計報告庫/財務審計/6903_巨漢/20260502/F07_存貨週轉效率同業對比_投資研究員.md"}'),l={name:"審計報告庫/財務審計/6903_巨漢/20260502/F07_存貨週轉效率同業對比_投資研究員.md"};function i(n,a,_,s,h,c){return e(),r("div",null,[...a[0]||(a[0]=[o('<h2 id="📋-審計題目" tabindex="-1">📋 審計題目 <a class="header-anchor" href="#📋-審計題目" aria-label="Permalink to &quot;📋 審計題目&quot;">​</a></h2><p>存貨週轉天數與同業相比是否具備競爭優勢？整體營運週期 (Cash Cycle) 是否處於擴張狀態？</p><h2 id="🎯-專家直斷" tabindex="-1">🎯 專家直斷 <a class="header-anchor" href="#🎯-專家直斷" aria-label="Permalink to &quot;🎯 專家直斷&quot;">​</a></h2><p>巨漢屬工程統包業，存貨極低（佔資產 &lt;0.5%），存貨週轉天數僅 5 天，遠優於製造業同業。營運週期 135 天完全由 DSO（130 天）驅動，存貨效率非此產業的競爭關鍵。重點在應收帳款管理而非存貨。</p><h2 id="📊-診斷評級" tabindex="-1">📊 診斷評級 <a class="header-anchor" href="#📊-診斷評級" aria-label="Permalink to &quot;📊 診斷評級&quot;">​</a></h2><p>A（優）。存貨週轉天數僅 5 天，優於製造業同業。營運週期 135 天，以工程統包業而言尚可，但 2025 年 DSO 從 67 天急升至 130 天，營運週期擴張一倍，資產效率明顯惡化。利空：若收款效率未改善，營運資金需求將持續攀升。</p><h2 id="🔍-答詢詳解" tabindex="-1">🔍 答詢詳解 <a class="header-anchor" href="#🔍-答詢詳解" aria-label="Permalink to &quot;🔍 答詢詳解&quot;">​</a></h2><ol><li><p><strong>存貨效率</strong>：存貨週轉天數 4-5 天，遠優於製造業同業（PCB 材料商通常 60-90 天），但這是產業特性使然——工程統包公司不需要大量備料。對比同業聖暉、帆宣等，存貨天數約 10-30 天，巨漢的 5 天仍屬前段班。</p></li><li><p><strong>營運週期分析</strong>：2024 年營運週期約 67 天（DSO 67 + DIO 0），2025 年擴大至 135 天（DSO 130 + DIO 5）。營運週期擴張 +101%，反映應收帳款回收顯著放緩，為資產效率失速的警訊。</p></li><li><p><strong>同業對比</strong>：台灣工程統包同業（聖暉、帆宣、亞翔）DSO 約 60-100 天，巨漢 2025 年 DSO 130 天已高於同業均值，表示收款效率落後。營運週期 135 天也高於同業平均（約 100-110 天）。</p></li></ol><h2 id="💡-專家評析" tabindex="-1">💡 專家評析 <a class="header-anchor" href="#💡-專家評析" aria-label="Permalink to &quot;💡 專家評析&quot;">​</a></h2><ol><li><strong>營運週期擴張的風險</strong>：營運週期從 67 天擴張至 135 天，資產效率惡化。若 2026 年無法回落至 100 天以下，公司將需要更多營運資金支撐同樣的營收規模，壓縮 ROIC。</li><li><strong>產業比較失真的注意</strong>：巨漢與傳統製造業比較存貨沒有意義。與工程統包同業比較 DSO 和營運週期才具參考價值——這方面巨漢處於落後位置。</li><li><strong>營運資金壓力</strong>：營運週期 135 天意味著每賺 1 元營收需要墊付約 0.37 元的營運資金（135/365）。以年營收 31.77 億計算，營運資金需求約 11.7 億，與帳上現金 17-22 億相比尚可支撐，但若持續擴張將吃掉現金。</li></ol><h2 id="📚-證據來源" tabindex="-1">📚 證據來源 <a class="header-anchor" href="#📚-證據來源" aria-label="Permalink to &quot;📚 證據來源&quot;">​</a></h2><ul><li>財務分析工具.py：inventory_check 6903</li><li>FinMind：TaiwanStockBalanceSheet、TaiwanStockFinancialStatements</li></ul>',12)])])}const u=t(l,[["render",i]]);export{p as __pageData,u as default};
